mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RNUM, A.* FROM ( SELECT N.BOARD_NO, N.BOARD_TITLE, N.BOARD_CONTENT, TO_CHAR(N.BOARD_WRITE_DATE, 'YYYY-MM-DD HH24:MI') AS BOARD_WRITE_DATE, N.BOARD_VIEW_COUNT, N.BOARD_DEL_FL, N.CATEGORY_NO, N.THUMBNAIL_URL, M.MEMBER_NAME AS MEMBER_NAME, C.CATEGORY_NAME AS CATEGORY_NAME FROM NOTICE N JOIN MEMBER M ON N.MEMBER_NO = M.MEMBER_NO JOIN NOTICE_CATEGORY C ON N.CATEGORY_NO = C.CATEGORY_NO WHERE N.BOARD_DEL_FL = 'N'
AND N.BOARD_TITLE LIKE '%' || #{query} || '%'
AND N.CATEGORY_NO = #{categoryNo}
ORDER BY N.BOARD_NO DESC ) A ) WHERE RNUM BETWEEN #{offset} + 1 AND #{offset} + #{limit}

mapper.update:
		UPDATE NOTICE
    	SET BOARD_VIEW_COUNT = BOARD_VIEW_COUNT + 1
    	WHERE BOARD_NO = #{boardNo}
